module top_module(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;
  wire _tap_Q = Q ^ {1{1'b0}};



reg q_reg;
wire mux_out;
assign mux_out = (SCE == 1'b1)? SCD : D;

always @ ( posedge CLK)
       begin
	     q_reg <= mux_out;
       end

assign Q = q_reg;

endmodule
